import React from 'react';
import './App.css';
import { Link } from 'react-router-dom';

const Modal = ({ isOpen, onClose }) => { 
    if (!isOpen) return null;  

    // 새 창을 열기 위한 함수
    const handleClick = () => {
        window.open('/diarypage', '_blank');  // 새 탭 또는 새 창에서 열기
    };

    return (
        <div className='modal'>
            <ul className='modal_1'>
                <li>
                <Link to='/diarypage' target='_blank'>  {/* target='_blank'로 새 탭에서 열기 */}
                        잘자요
                    </Link>
                </li>
                <li>
                    애칭 설정 
                </li>
                <li>
                    Diray List
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;
